//@ edition: 2021
//@ proc-macro: proc_macro_demo_helper.rs

// Regression test for functions whose bodies consist entirely of code
// generated by a proc-macro expansion (e.g. the impls generated by a
// `#[derive(...)]` macro, or a function body generated by an attribute
// macro). All of their statement spans point at the macro invocation site,
// and between Rust 1.83 and 1.84 the span refinement changes caused all of
// those spans to be discarded, leaving such functions either completely
// uninstrumented or (in some versions) with a single leftover region wired
// to an arbitrary non-entry counter that reads 0 forever.
//
// The desired behavior is that the visible macro invocation site (the derive
// macro path, or the attribute) gets a region wired to the generated
// function's *entry* counter, so the invocation line reports how many times
// the generated code was executed. Generated functions that are never called
// mark their invocation site as executable-but-unexecuted (count 0), which is
// covered as soon as any sibling function from the same invocation runs.

extern crate proc_macro_demo_helper;
use proc_macro_demo_helper::{Demo, generate_body};

// Generates `demo` (called 3 times below) and `never_called` (never called).
// This line should report the total execution count of the generated code.
#[derive(Demo)]
struct Used;

// Same derive, but nothing generated from it is ever called, and the type
// itself is unused. This line is executable but reports 0.
#[derive(Demo)]
struct Unused;

// The function body is replaced entirely with generated code. The attribute
// line reports the number of calls to the generated function.
#[generate_body]
fn attr_generated(_: ()) {}

fn main() {
    assert_eq!(Used.demo(1), 2);
    assert_eq!(Used.demo(50), 100);
    assert_eq!(Used.demo(100), 200);
    assert_eq!(attr_generated(20), 40);
}
